import type { Metadata } from "next";
import { Inter } from "next/font/google";
import "./globals.css";

const inter = Inter({ subsets: ["latin"], variable: "--font-inter" });

export const metadata: Metadata = {
  title: "Material Request System",
  description: "A premium application to manage material requests.",
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en" className={`${inter.variable} antialiased dark`}>
      <body className="min-h-screen bg-slate-900 text-slate-50 selection:bg-indigo-500/30">
        <div className="relative flex min-h-screen flex-col">
          {/* Subtle background decoration */}
          <div className="absolute top-0 left-0 w-full h-[500px] bg-indigo-500/10 blur-[120px] rounded-full -z-10 transform -translate-y-1/2 pointer-events-none"></div>

          <header className="sticky top-0 z-50 w-full border-b border-white/10 glass-panel">
            <div className="container mx-auto flex h-16 items-center px-4">
              <a href="/" className="flex items-center gap-2">
                <span className="text-xl font-bold tracking-tight gradient-text">MaterialRequests</span>
              </a>
            </div>
          </header>

          <main className="flex-1 container mx-auto p-4 md:p-8">
            {children}
          </main>
        </div>
      </body>
    </html>
  );
}
